'use client'
import { createMachine, signal, useMachine, useSignalEffect, useSignals } from '@cascivo/core'
import { builtin, t } from '@cascivo/i18n'
import { useRef, type ReactNode } from 'react'
import styles from './toast.module.css'

export type ToastVariant = 'default' | 'success' | 'warning' | 'destructive'

export interface ToastOptions {
  title: string
  description?: string
  variant?: ToastVariant
  duration?: number
}

interface ToastRecord extends ToastOptions {
  id: number
}

const MAX_VISIBLE = 3
const DEFAULT_DURATION = 5000
// must outlast --cascivo-motion-exit (150ms)
const EXIT_DURATION = 160

// App-global queue: toasts are not tied to a single render tree, so a module
// signal lets useToast() enqueue from anywhere without React context.
let nextToastId = 0
const toastQueue = signal<ToastRecord[]>([])

function enqueue(options: ToastOptions) {
  toastQueue.value = [...toastQueue.value, { id: nextToastId++, ...options }]
}

function dequeue(id: number) {
  toastQueue.value = toastQueue.value.filter((toast) => toast.id !== id)
}

export function ToastProvider({ children }: { children: ReactNode }) {
  useSignals()
  const visible = toastQueue.value.slice(-MAX_VISIBLE)

  return (
    <>
      {children}
      <div className={styles['viewport']} role="region" aria-label={t(builtin.toast.region)}>
        {visible.map((toast) => (
          <ToastItem key={toast.id} toast={toast} onDismiss={() => dequeue(toast.id)} />
        ))}
      </div>
    </>
  )
}

const machine = createMachine({
  initial: 'visible' as const,
  states: {
    visible: { on: { DISMISS: 'dismissing' } },
    dismissing: { on: { END: 'gone' } },
  },
})

function ToastItem({ toast, onDismiss }: { toast: ToastRecord; onDismiss: () => void }) {
  useSignals()
  const [state, send] = useMachine(machine)
  const onDismissRef = useRef(onDismiss)
  onDismissRef.current = onDismiss

  const duration = toast.duration ?? DEFAULT_DURATION
  const assertive = toast.variant === 'destructive'

  useSignalEffect(() => {
    const phase = state.value
    if (phase === 'visible') {
      const timer = setTimeout(() => send('DISMISS'), duration)
      return () => clearTimeout(timer)
    }
    if (phase === 'dismissing') {
      const timer = setTimeout(() => onDismissRef.current(), EXIT_DURATION)
      return () => clearTimeout(timer)
    }
    return undefined
  })

  return (
    <div
      role={assertive ? 'alert' : 'status'}
      aria-live={assertive ? 'assertive' : 'polite'}
      data-variant={toast.variant ?? 'default'}
      data-state={state.value}
      className={styles['toast']}
    >
      <div className={styles['body']}>
        <div className={styles['title']}>{toast.title}</div>
        {toast.description && <div className={styles['description']}>{toast.description}</div>}
      </div>
      <button
        type="button"
        className={styles['close']}
        aria-label={t(builtin.toast.dismiss)}
        onClick={() => send('DISMISS')}
      >
        ✕
      </button>
    </div>
  )
}

/**
 * Returns `{ toast }` — an object, not a callable. Destructure it and call
 * `toast(...)`:
 *
 * ```tsx
 * const { toast } = useToast()
 * toast({ title: 'Saved' })
 * ```
 *
 * (`useToast()(...)` is a type error — the hook returns the namespace object so
 * more helpers can be added without changing its shape.)
 */
export function useToast() {
  return { toast: enqueue }
}

export function dismissAllToasts() {
  toastQueue.value = []
}

@layer cascivo.component {
  .viewport {
    position: fixed;
    inset-block-end: var(--cascivo-space-4);
    inset-inline-end: var(--cascivo-space-4);
    z-index: var(--cascivo-z-toast);
    display: flex;
    flex-direction: column;
    gap: var(--cascivo-space-2);
    inline-size: min(24rem, calc(100vw - var(--cascivo-space-8)));
    pointer-events: none;

    /* Fixed-position viewport-level overlay: it responds to the viewport, not to a
       containing element, so this must be a viewport @media query. As an unnamed
       @container query it never matched (nothing establishes containment around the
       portal root), so the narrow-screen edge-to-edge layout never applied. */
    @media (max-width: 30rem) {
      inset-inline: var(--cascivo-space-4);
      inline-size: auto;
    }
  }

  .toast {
    display: flex;
    align-items: flex-start;
    gap: var(--cascivo-space-3);
    padding: var(--cascivo-space-4);
    max-inline-size: calc(min(28rem, 100vw) - var(--cascivo-space-4, 1rem));
    background-color: var(--cascivo-color-surface-overlay);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-overlay);
    box-shadow: var(--cascivo-shadow-overlay);
    pointer-events: auto;
    opacity: 1;
    translate: 0 0;
    transition:
      opacity var(--cascivo-motion-enter),
      translate var(--cascivo-motion-enter);

    /* Enter: animate from the styles the browser applies on first render */
    @starting-style {
      opacity: 0;
      translate: 0 var(--cascivo-space-4);
    }

    &[data-state='dismissing'],
    &[data-state='gone'] {
      opacity: 0;
      translate: 0 var(--cascivo-space-4);
      transition:
        opacity var(--cascivo-motion-exit),
        translate var(--cascivo-motion-exit);
    }

    &[data-variant='success'] {
      border-color: color-mix(
        in oklch,
        var(--cascivo-color-success) 35%,
        var(--cascivo-color-border)
      );
    }
    &[data-variant='success'] .icon,
    &[data-variant='success'] .title {
      color: var(--cascivo-color-success);
    }

    &[data-variant='warning'] {
      border-color: color-mix(
        in oklch,
        var(--cascivo-color-warning) 35%,
        var(--cascivo-color-border)
      );
    }
    &[data-variant='warning'] .icon,
    &[data-variant='warning'] .title {
      color: var(--cascivo-color-warning);
    }

    &[data-variant='destructive'] {
      border-color: color-mix(
        in oklch,
        var(--cascivo-color-destructive) 35%,
        var(--cascivo-color-border)
      );
    }
    &[data-variant='destructive'] .icon,
    &[data-variant='destructive'] .title {
      color: var(--cascivo-color-destructive);
    }
  }

  .body {
    display: flex;
    flex-direction: column;
    gap: var(--cascivo-space-1);
    flex: 1;
    min-inline-size: 0;
  }

  .title {
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-sm);
    font-weight: var(--cascivo-font-semibold);
    color: var(--cascivo-color-text);
    line-height: var(--cascivo-leading-snug);
  }

  .description {
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text-subtle);
    line-height: var(--cascivo-leading-normal);
  }

  .close {
    display: flex;
    flex-shrink: 0;
    align-items: center;
    justify-content: center;
    inline-size: 1.5rem;
    block-size: 1.5rem;
    padding: 0;
    font-size: var(--cascivo-text-xs);
    color: var(--cascivo-color-text-muted);
    background: transparent;
    border: none;
    border-radius: var(--cascivo-radius-control);
    cursor: pointer;
    transition: color var(--cascivo-duration-150) var(--cascivo-ease-out);

    &:hover {
      color: var(--cascivo-color-text);
    }

    &:focus-visible {
      outline: none;
      box-shadow: var(--cascivo-focus-ring);
    }
  }
}

@media (forced-colors: active) {
  .toast {
    border: 1px solid CanvasText;
  }

  .close:focus-visible {
    outline: 2px solid Highlight;
    outline-offset: 2px;
  }
}
